import (
	"fmt"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
)

// Issuer creates signed JWT tokens.
type Issuer struct {
	secret   []byte
	duration time.Duration
}

// NewIssuer creates a new token issuer with the given HMAC secret and token duration.
func NewIssuer(secret string, duration time.Duration) *Issuer {
	return &Issuer{
		secret:   []byte(secret),
		duration: duration,
	}
}

// Issue creates and signs a new JWT for the given user.
func (iss *Issuer) Issue(userID uuid.UUID, email, clientType string) (string, error) {
	now := time.Now()
	claims := &Claims{
		UserID:     userID,
		Email:      email,
		ClientType: clientType,
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   userID.String(),
			IssuedAt:  jwt.NewNumericDate(now),
			ExpiresAt: jwt.NewNumericDate(now.Add(iss.duration)),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	signed, err := token.SignedString(iss.secret)
	if err != nil {
		return "", fmt.Errorf("auth: issue token: %w", err)
	}
	return signed, nil
}
