)

// ErrEmailTaken is returned when a registration uses an already-taken email.
var ErrEmailTaken = errors.New("user: email already taken")

// ErrNotFound is returned when a user lookup finds no matching row.
var ErrNotFound = errors.New("user: not found")

// User represents a row in the users table.
type User struct {
	ID           uuid.UUID
	Email        string
	DisplayName  *string
	PasswordHash *string
	AuthProvider string
	Settings     map[string]any
	CreatedAt    time.Time
	UpdatedAt    time.Time
}

// userColumns is the canonical SELECT column list for the users table.
const userColumns = `id, email, display_name, password_hash, auth_provider, settings, created_at, updated_at`

// Service provides user CRUD operations.
type Service struct {
	pool *pgxpool.Pool
}

// New creates a new user Service.
func New(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// Create registers a new local user with email/password authentication.
func (s *Service) Create(ctx context.Context, email, password, displayName string) (*User, error) {
	email = strings.TrimSpace(strings.ToLower(email))
	if !strings.Contains(email, "@") || email == "" {
		return nil, fmt.Errorf("user: create: invalid email")
	}
	if len(password) < 8 {
		return nil, fmt.Errorf("user: create: password must be at least 8 characters")
	}

	hash, err := auth.HashPassword(password)
	if err != nil {
		return nil, fmt.Errorf("user: create: %w", err)
	}

	var dn *string
	if displayName != "" {
		displayName = strings.TrimSpace(displayName)
		dn = &displayName
	}

	query := fmt.Sprintf(`INSERT INTO users (email, display_name, password_hash, auth_provider)
		VALUES ($1, $2, $3, 'local')
		RETURNING %s`, userColumns)

	row := s.pool.QueryRow(ctx, query, email, dn, hash)
	u, err := scanUser(row)
	if err != nil {
		var pgErr *pgconn.PgError
		if errors.As(err, &pgErr) && pgErr.Code == "23505" {
			return nil, ErrEmailTaken
		}
		return nil, fmt.Errorf("user: create: %w", err)
	}
	return u, nil
}

// GetByEmail returns a user by email. Returns nil, nil if not found.
func (s *Service) GetByEmail(ctx context.Context, email string) (*User, error) {
	email = strings.TrimSpace(strings.ToLower(email))
	query := fmt.Sprintf(`SELECT %s FROM users WHERE email = $1`, userColumns)
	row := s.pool.QueryRow(ctx, query, email)
	u, err := scanUser(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("user: get by email: %w", err)
	}
	return u, nil
}

// GetByID returns a user by ID. Returns nil, nil if not found.
func (s *Service) GetByID(ctx context.Context, id uuid.UUID) (*User, error) {
	query := fmt.Sprintf(`SELECT %s FROM users WHERE id = $1`, userColumns)
	row := s.pool.QueryRow(ctx, query, id)
	u, err := scanUser(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("user: get by id: %w", err)
	}
	return u, nil
}

// scanUser scans a single user row.
func scanUser(row pgx.Row) (*User, error) {
	var u User
	err := row.Scan(
		&u.ID,
		&u.Email,
		&u.DisplayName,
		&u.PasswordHash,
		&u.AuthProvider,
		&u.Settings,
		&u.CreatedAt,
		&u.UpdatedAt,
	)
	if err != nil {
		return nil, err
	}
	return &u, nil
}
